class Mon:
    def __init__(self, name, type, type2 , hp, at, de, sp_at, sp_de, spd,):
        self.name = name
        self.type = type
        self.type2 = type2
        self.hp = hp
        self.at = at   
        self.de = de
        self.sp_at = sp_at   
        self.sp_de = sp_de
        self.spd = spd


    def call(self):
        return f"{self.name}"
    
